-- Migration number: 0016    Move hardcoded groups and characters to database

-- AI群组表
CREATE TABLE IF NOT EXISTS ai_groups (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT DEFAULT '',
    members TEXT DEFAULT '[]',
    is_group_discussion_mode INTEGER DEFAULT 0,
    chat_mode TEXT DEFAULT 'interaction',
    type TEXT DEFAULT 'ai',
    claw_group_id TEXT,
    sort_order INTEGER DEFAULT 0,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- AI角色表
CREATE TABLE IF NOT EXISTS ai_characters (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    personality TEXT DEFAULT '',
    model TEXT NOT NULL,
    avatar TEXT DEFAULT '',
    custom_prompt TEXT DEFAULT '',
    tags TEXT DEFAULT '[]',
    stages TEXT DEFAULT '[]',
    sort_order INTEGER DEFAULT 0,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

